'use client'

import { motion, useMotionValue, useSpring } from 'framer-motion'
import { useT } from '@/lib/LanguageContext'

/**
 * ⚠️ REPLACE WITH REAL NUMBER (international format, no + or spaces).
 *    For Serbia: country code 381 + number without leading 0.
 *    Example: 0601234567 → 381601234567
 */
const PHONE = '381601234567'

function WhatsAppIcon({ size = 26 }: { size?: number }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="currentColor" aria-hidden>
      <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.693.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.890-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"/>
    </svg>
  )
}

export default function WhatsAppButton() {
  const t = useT()

  // Magnetic spring-follow
  const x  = useMotionValue(0)
  const y  = useMotionValue(0)
  const sx = useSpring(x, { damping: 18, stiffness: 280 })
  const sy = useSpring(y, { damping: 18, stiffness: 280 })

  const handleMove = (e: React.MouseEvent<HTMLAnchorElement>) => {
    const rect = e.currentTarget.getBoundingClientRect()
    x.set((e.clientX - rect.left - rect.width  / 2) * 0.35)
    y.set((e.clientY - rect.top  - rect.height / 2) * 0.35)
  }

  const handleLeave = () => { x.set(0); y.set(0) }

  const href = `https://wa.me/${PHONE}?text=${encodeURIComponent(t.whatsapp.greeting)}`

  return (
    <motion.a
      href={href}
      target="_blank"
      rel="noopener noreferrer"
      aria-label={t.aria.whatsapp}
      onMouseMove={handleMove}
      onMouseLeave={handleLeave}
      initial={{ opacity: 0, scale: 0.6, y: 20 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      transition={{ type: 'spring', damping: 18, stiffness: 200, delay: 1.4 }}
      whileHover={{ scale: 1.08 }}
      whileTap={{ scale: 0.94 }}
      style={{
        position: 'fixed',
        bottom: '24px',
        right: '24px',
        width: '54px',
        height: '54px',
        borderRadius: '50%',
        backgroundColor: '#25D366',
        color: '#fff',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        textDecoration: 'none',
        boxShadow: '0 10px 28px rgba(37, 211, 102, 0.42), 0 2px 6px rgba(0,0,0,0.15)',
        zIndex: 60,
        x: sx,
        y: sy,
      }}
    >
      {/* Pulsing ring */}
      <motion.span
        aria-hidden
        animate={{ scale: [1, 1.55, 1.55], opacity: [0.45, 0, 0] }}
        transition={{ duration: 2.6, repeat: Infinity, ease: 'easeOut' }}
        style={{
          position: 'absolute',
          inset: 0,
          borderRadius: '50%',
          backgroundColor: '#25D366',
          zIndex: -1,
        }}
      />
      <WhatsAppIcon size={26} />
    </motion.a>
  )
}
